class MedicalExtract(BaseModel):
    model_config = {"extra": "forbid"}
    refusal: str | None = Field(
        default=None,
        description="If you cannot/should not answer, explain here. Else null.",
    )
    diagnoses: list[str] | None = None
    medications: list[str] | None = None

resp = client.responses.parse(model="gpt-5", input=msgs, text_format=MedicalExtract)
if resp.output_parsed.refusal:
    log_refusal(resp.output_parsed.refusal)
    return None
return resp.output_parsed
